import React, { useState } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import { useTheme } from '../hooks/useTheme';

export default function Sidebar() {
  const { user, logout } = useAuth();
  const { theme, toggle } = useTheme();
  const navigate = useNavigate();
  const isStaff = user?.userType === 'user';
  const isDark = theme === 'dark';

  const navItems = [
    { path:'/dashboard',        label:'Dashboard',      show:true },
    { path:'/books',            label:'Books',           show:true },
    { path:'/members',          label:'Members',         show:isStaff },
    { path:'/requests',         label:'Borrow Requests', show:isStaff },
    { path:'/borrows',          label:'Borrows',         show:isStaff },
    { path:'/categories',       label:'Categories',      show:true },
    { path:'/create-assistant', label:'Add Assistant',   show:user?.role==='librarian' },
    { path:'/my-borrows',       label:'My Library',      show:!isStaff },
  ];

  const roleLabel:any = { librarian:'Librarian', library_assistant:'Library Assistant', student:'Student', staff:'Staff Member' };
  const roleColor:any = { librarian:'#c9a84c', library_assistant:'#10b981', student:'#60a5fa', staff:'#a78bfa' };
  const rc = roleColor[user?.role||''] || '#c9a84c';

  return (
    <>
      <style>{`
        .nav-lnk {
          display:block; padding:10px 16px; border-radius:10px;
          font-size:14px; font-weight:500;
          color:rgba(255,255,255,0.42); text-decoration:none;
          margin-bottom:2px; transition:all .18s; position:relative;
        }
        .nav-lnk::before {
          content:''; position:absolute; left:0; top:18%; bottom:18%;
          width:3px; background:#c9a84c; border-radius:0 3px 3px 0;
          opacity:0; transform:scaleY(0); transition:all .18s;
        }
        .nav-lnk:hover { color:rgba(255,255,255,0.82); background:rgba(255,255,255,0.07); }
        .nav-lnk.active { color:#fff !important; background:rgba(201,168,76,0.14) !important; font-weight:700 !important; }
        .nav-lnk.active::before { opacity:1; transform:scaleY(1); }
        .so-btn:hover { color:#f87171 !important; background:rgba(239,68,68,0.08) !important; border-color:rgba(239,68,68,0.15) !important; }
        .theme-btn:hover { filter:brightness(1.2); }
      `}</style>

      <aside style={{ width:240, minHeight:'100vh', background:'#080812', borderRight:'1px solid rgba(255,255,255,0.05)', display:'flex', flexDirection:'column', flexShrink:0 }}>

        {/* Top glow */}
        <div style={{ position:'absolute', top:0, left:0, width:240, height:140, background:'radial-gradient(ellipse at top left,rgba(201,168,76,0.07),transparent 70%)', pointerEvents:'none' }} />

        {/* Logo */}
        <div style={{ padding:'26px 20px 20px', borderBottom:'1px solid rgba(255,255,255,0.05)' }}>
          <div style={{ fontFamily:"'Playfair Display',serif", fontSize:21, fontWeight:700, color:'#fff', letterSpacing:'-0.3px' }}>LibraryMS</div>
          <div style={{ fontSize:10, color:'rgba(201,168,76,0.5)', letterSpacing:'2px', textTransform:'uppercase', marginTop:3, fontWeight:600 }}>BAUST · University Library</div>
          <div style={{ marginTop:14, height:1, background:'linear-gradient(90deg,rgba(201,168,76,0.35),transparent)' }}/>
        </div>

        {/* Nav */}
        <nav style={{ flex:1, padding:'18px 12px', overflowY:'auto' }}>
          <div style={{ fontSize:10, fontWeight:700, color:'rgba(255,255,255,0.15)', letterSpacing:'2px', textTransform:'uppercase', padding:'0 6px', marginBottom:10 }}>Navigation</div>
          {navItems.filter(i=>i.show).map(item=>(
            <NavLink key={item.path} to={item.path} className={({isActive})=>`nav-lnk${isActive?' active':''}`}>
              {item.label}
            </NavLink>
          ))}
        </nav>

        {/* Theme Toggle */}
        <div style={{ padding:'0 14px 10px' }}>
          <button className="theme-btn" onClick={toggle}
            style={{ width:'100%', display:'flex', alignItems:'center', justifyContent:'space-between', padding:'10px 14px', borderRadius:11, background:'rgba(255,255,255,0.04)', border:'1px solid rgba(255,255,255,0.07)', cursor:'pointer', fontFamily:'inherit', transition:'all .2s' }}>
            <span style={{ fontSize:13, color:'rgba(255,255,255,0.45)', fontWeight:600 }}>
              {isDark ? 'Dark Mode' : 'Light Mode'}
            </span>
            {/* Toggle pill */}
            <div style={{ width:44, height:24, borderRadius:99, background:isDark?'rgba(255,255,255,0.1)':'#c9a84c', position:'relative', transition:'background .3s', flexShrink:0 }}>
              <div style={{ position:'absolute', top:3, left:isDark?3:23, width:18, height:18, borderRadius:'50%', background:isDark?'rgba(255,255,255,0.5)':'#fff', transition:'left .3s', boxShadow:'0 1px 4px rgba(0,0,0,0.3)' }}/>
            </div>
          </button>
        </div>

        {/* User */}
        <div style={{ padding:'8px 14px 20px', borderTop:'1px solid rgba(255,255,255,0.05)' }}>
          <div style={{ background:'rgba(255,255,255,0.03)', border:'1px solid rgba(255,255,255,0.06)', borderRadius:13, padding:'13px', marginBottom:8 }}>
            <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:user?.member_id?9:0 }}>
              <div style={{ width:36, height:36, borderRadius:'50%', background:`linear-gradient(135deg,${rc},${rc}66)`, border:`2px solid ${rc}44`, display:'flex', alignItems:'center', justifyContent:'center', fontWeight:800, color:'#fff', fontSize:15, flexShrink:0, boxShadow:`0 0 14px ${rc}30` }}>
                {user?.name?.charAt(0).toUpperCase()}
              </div>
              <div style={{ minWidth:0, flex:1 }}>
                <div style={{ fontSize:13, fontWeight:700, color:'#fff', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{user?.name}</div>
                <div style={{ fontSize:11, color:rc, marginTop:1, fontWeight:600 }}>{roleLabel[user?.role||'']||user?.role}</div>
              </div>
            </div>
            {user?.member_id && (
              <div style={{ background:'rgba(0,0,0,0.25)', borderRadius:7, padding:'4px 9px', display:'inline-flex', alignItems:'center', gap:5 }}>
                <span style={{ fontSize:9, color:'rgba(255,255,255,0.2)', fontWeight:700, letterSpacing:'1px', textTransform:'uppercase' }}>ID</span>
                <span style={{ fontSize:11, color:'rgba(255,255,255,0.45)', fontFamily:'monospace', fontWeight:600 }}>{user.member_id}</span>
              </div>
            )}
          </div>
          <button className="so-btn"
            onClick={()=>{ logout(); navigate('/login'); }}
            style={{ width:'100%', display:'flex', alignItems:'center', justifyContent:'center', gap:8, padding:'9px', borderRadius:10, fontSize:13, fontWeight:600, color:'rgba(255,255,255,0.28)', background:'transparent', border:'1px solid rgba(255,255,255,0.06)', cursor:'pointer', fontFamily:'inherit', transition:'all .18s' }}>
            ⎋ Sign Out
          </button>
        </div>
      </aside>
    </>
  );
}
